final:
module top_module (
    input [2:0] s,
    output reg not_c
);

    always @(*) begin
        case (s)
            3'b000: not_c = 1;
            3'b001: not_c = 0;
            3'b010: not_c = 1;
            3'b011: not_c = 0;
            3'b100: not_c = 1;
            3'b101: not_c = 0;
            3'b110: not_c = 1;
            3'b111: not_c = 0;
            default: not_c = 0; // Default case
        endcase
    end
endmodule
